/**
   * Professions.ts — Star-Wars-Galaxies-style profession trees.
   *
   * Source of truth: docs/inventory/professions.csv. The branch/skill arrays
   * below were generated from that CSV (see scripts/genProfessions if/when
   * regenerated). Do NOT edit individual skill entries by hand here without
   * also updating the CSV.
   *
   * 7 professions × 5 branches × 4 ranks + 1 Master per profession = 147
   * skills. Each profession earns its own XP from in-game activities (see
   * `ProfessionsService` for the runtime + persistence layer). Spending
   * profession XP unlocks skills which expose passive bonuses the engine
   * can read at runtime.
   *
   * Designed so it does NOT conflict with the existing 4-track PerksBook —
   * that system continues to spend `playerStats.skillPoints` from
   * level-ups; this system spends per-profession XP earned independently.
   */

  // ─── Profession identifiers ──────────────────────────────────────────────────

  export const PROFESSIONS = [
    'gathering',
    'hunting',
    'crafting',
    'township',
    'survival',
    'chemistry',
    'combat',
  ] as const;

  export type Profession = typeof PROFESSIONS[number];

  export interface ProfessionMeta {
    id: Profession;
    label: string;
    blurb: string;
    color: string;
    /** Hero icon shown on tab + summary. */
    icon: string;
  }

