  // ─── Effect keys (passives the engine reads) ─────────────────────────────────
  //
  // String-typed for forward compatibility with new CSV-driven keys. Engine
  // consumers (`ProfessionsService.getEffect('bountyXpBonus')`) keep the same
  // API; new keys can be added by editing the CSV alone.
  export type ProfessionEffectKey = string;
  export type ProfessionEffects = Record<ProfessionEffectKey, number>;

  // Boolean / string passives ("frostbiteImmunity true", "harvesterUnlocked
  // forager") are kept separately on each skill via `extras`. They are not
  // summed; the runtime can probe them via `hasFlag` / `getUnlock` below.
  export type ProfessionExtras = Record<string, boolean | string>;

  // ─── Skill definition ───────────────────────────────────────────────────────

  export interface ProfessionSkill {
    id: string;                          // unique across all professions
    prof: Profession;
    branch: string;                      // branch slug, or 'master'
    rank: 1 | 2 | 3 | 4 | 'M';
    name: string;
    desc: string;
    /** XP cost in the OWNING profession to learn this skill. */
    cost: number;
    /** Other skill ids the player must already own. */
    prereq: string[];
    /** Resolved icon URL. */
    icon: string;
    /** Signature item that thematically pairs with the skill (display only). */
    signature: string;
    /** Recipe ids granted on learn (display only — engine picks them up via id). */
    recipes: string[];
    /** Numeric passives summed by `aggregatePassives`. */
    passive: ProfessionEffects;
    /** Boolean / string passives (flags, unlocks) — not summed. */
    extras: ProfessionExtras;
  }

  export type ProfessionMaster = ProfessionSkill & { rank: 'M' };

  export interface ProfessionBranch {
    id: string;
    prof: Profession;
    label: string;
    skills: ProfessionSkill[];
  }

  // ─── Branch + master data, generated from professions.csv ───────────────────

