export const PROFESSION_MASTERS: Record<Profession, ProfessionMaster | null> = {
  gathering: MASTER_GATHERING,
  hunting: MASTER_HUNTING,
  crafting: MASTER_CRAFTING,
  township: MASTER_TOWNSHIP,
  survival: MASTER_SURVIVAL,
  chemistry: MASTER_CHEMISTRY,
  combat: MASTER_COMBAT,
};


  /** Flat lookup of every skill (branches + masters). */
  export const ALL_SKILLS: ProfessionSkill[] = (PROFESSIONS).flatMap(p => {
    const list: ProfessionSkill[] = PROFESSION_BRANCHES[p].flatMap(b => b.skills);
    const m = PROFESSION_MASTERS[p];
    if (m) list.push(m);
    return list;
  });

  const SKILL_BY_ID: Record<string, ProfessionSkill> = Object.fromEntries(
    ALL_SKILLS.map(s => [s.id, s]),
  );

  export function getSkill(id: string): ProfessionSkill | undefined {
    return SKILL_BY_ID[id];
  }

  // ─── Effect aggregation ─────────────────────────────────────────────────────

  /** Sum the numeric passive effects of every learned skill. */
  export function aggregatePassives(learned: Iterable<string>): ProfessionEffects {
    const out: ProfessionEffects = {};
    for (const id of learned) {
      const s = SKILL_BY_ID[id];
      if (!s) continue;
      for (const [k, v] of Object.entries(s.passive)) {
        out[k] = (out[k] ?? 0) + v;
      }
    }
    return out;
  }

  /** Returns true if any learned skill has the boolean flag set. */
  export function hasFlag(learned: Iterable<string>, flag: string): boolean {
    for (const id of learned) {
      const s = SKILL_BY_ID[id];
      if (s && s.extras[flag] === true) return true;
    }
    return false;
  }

  /** Collect the set of string-valued unlocks (e.g. all "harvesterUnlocked X"). */
  export function getUnlocks(learned: Iterable<string>, key: string): string[] {
    const out = new Set<string>();
    for (const id of learned) {
      const s = SKILL_BY_ID[id];
      const v = s?.extras[key];
      if (typeof v === 'string') out.add(v);
    }
    return [...out];
  }

  // ─── Persistence shape ──────────────────────────────────────────────────────

  export interface ProfessionState {
    /** XP earned per profession (only spent XP is removed). */
    xp: Partial<Record<Profession, number>>;
    /** Skill ids the player has learned (de-duplicated). */
    learned: string[];
  }

  export const EMPTY_PROFESSION_STATE: ProfessionState = { xp: {}, learned: [] };
  